require_once __DIR__.'/functions.php';if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$postId=filter_input(INPUT_POST,'post_id',FILTER_VALIDATE_INT);$reaction=filter_input(INPUT_POST,'reaction',FILTER_VALIDATE_INT);if(!$postId||!in_array($reaction,[-1,1],true)){http_response_code(400);exit('Reacción inválida.');}if(is_logged_in()&&current_user_id()){$table='post_staff_reactions';$column='user_id';$actor=current_user_id();}else{$member=require_member();$table='post_reactions';$column='member_id';$actor=(int)$member['id'];}$stmt=db()->prepare("SELECT reaction FROM {$table} WHERE post_id=? AND {$column}=?");$stmt->execute([$postId,$actor]);$current=(int)($stmt->fetchColumn()?:0);if($current===$reaction){db()->prepare("DELETE FROM {$table} WHERE post_id=? AND {$column}=?")->execute([$postId,$actor]);}else{db()->prepare("INSERT INTO {$table}(post_id,{$column},reaction) VALUES(?,?,?) ON DUPLICATE KEY UPDATE reaction=VALUES(reaction),updated_at=NOW()")->execute([$postId,$actor,$reaction]);}$stmt=db()->prepare('SELECT slug FROM posts WHERE id=?');$stmt->execute([$postId]);redirect('/'.rawurlencode((string)$stmt->fetchColumn()));
